import { syntaxTree } from '@codemirror/language';
import { RangeSetBuilder } from '@codemirror/state';
import type {
  Decoration,
  DecorationSet,
  EditorView,
  ViewUpdate,
} from '@codemirror/view';
import { ViewPlugin } from '@codemirror/view';

import {
  incompleteStatementMark,
  intermediateStatementMark,
  pastingMark,
  statementMark,
} from './decoration-marks.js';
import { pastingMode } from '../editor-state-configs/editor-config.js';
import { NEEDS_ESCAPING_REGEX } from '../utils/escape-suggestion.js';
import { getStatementStatus } from '../utils/get-statement-status.js';

type StatementDecoration = {
  from: number;
  to: number;
  mark: Decoration;
  statementType: 'complete' | 'incomplete' | 'indeterminate';
};

const needsEscapingRegex = new RegExp(NEEDS_ESCAPING_REGEX);

/**
 * Get the mark for a statement based on its status.
 */
function getStatementMark(
  statementType: 'complete' | 'incomplete' | 'indeterminate',
) {
  if (statementType === 'complete') {
    return statementMark;
  }
  if (statementType === 'indeterminate') {
    return intermediateStatementMark;
  }
  return incompleteStatementMark;
}

/**
 * When pasted content has special characters, merge statements that overlap or
 * touch the pasted range into a single range. Returns the merged range or null
 * if no statement was affected.
 */
function getMergedPasteRange(
  statementFrom: number,
  statementTo: number,
  pastedRange: { from: number; to: number },
  currentMerged: { from: number; to: number } | null,
): { from: number; to: number } {
  const rangeFrom = Math.min(statementFrom, pastedRange.from);
  const rangeTo = Math.max(statementTo, pastedRange.to);

  if (currentMerged === null) {
    return { from: rangeFrom, to: rangeTo };
  }

  return {
    from: Math.min(currentMerged.from, rangeFrom),
    to: Math.max(currentMerged.to, rangeTo),
  };
}

/**
 * Check whether the pasted range overlaps, touches, or is separated from the
 * statement only by whitespace.  This handles the case where the parser's
 * FilterStatement node does not include trailing whitespace but the paste
 * starts right after that whitespace (e.g. pasting in the value position of
 * `a = `).
 *
 * Complete statements separated by whitespace are NOT considered adjacent —
 * pasting after `a = b ` should create a new bubble, not merge into the
 * existing one.
 */
function isPasteAdjacentToStatement(
  pastedRange: { from: number; to: number },
  statementFrom: number,
  statementTo: number,
  doc: string,
  statementType: 'complete' | 'incomplete' | 'indeterminate',
): boolean {
  // Direct overlap or touch.
  if (pastedRange.from <= statementTo && pastedRange.to >= statementFrom) {
    return true;
  }

  // Don't merge across whitespace gaps for complete statements when the paste
  // is after the statement — they are finished and the pasted content should
  // form its own bubble.
  if (statementType === 'complete' && pastedRange.from > statementTo) {
    return false;
  }

  // Check if only whitespace separates them.
  const gap =
    pastedRange.from > statementTo
      ? doc.slice(statementTo, pastedRange.from)
      : doc.slice(pastedRange.to, statementFrom);
  return gap.trim() === '';
}

/**
 * Iterate over all FilterStatement nodes and collect decorations, identifying
 * which statements overlap or touch the pasted range for later merging.
 */
function collectRawDecorations(
  view: EditorView,
  pastedRange: { from: number; to: number } | undefined,
): {
  decorations: StatementDecoration[];
  mergedPasteRange: { from: number; to: number } | null;
  doc: string;
} {
  const decorations: StatementDecoration[] = [];
  let mergedPasteRange: { from: number; to: number } | null = null;
  const doc = view.state.doc.toString();

  for (const { from, to } of view.visibleRanges) {
    syntaxTree(view.state).iterate({
      from,
      to,
      enter: (node) => {
        if (node.name === 'FilterStatement') {
          const { from: statementFrom, to: statementTo } = node;
          const statementType = getStatementStatus(node.node.cursor(), doc);

          // Check adjacency against the original paste range AND the growing
          // merged range so that statements on both sides get included.
          const shouldMerge =
            pastedRange &&
            (isPasteAdjacentToStatement(
              pastedRange,
              statementFrom,
              statementTo,
              doc,
              statementType,
            ) ||
              (mergedPasteRange &&
                isPasteAdjacentToStatement(
                  mergedPasteRange,
                  statementFrom,
                  statementTo,
                  doc,
                  statementType,
                )));

          if (shouldMerge) {
            mergedPasteRange = getMergedPasteRange(
              statementFrom,
              statementTo,
              pastedRange,
              mergedPasteRange,
            );
          } else {
            decorations.push({
              from: statementFrom,
              to: statementTo,
              mark: getStatementMark(statementType),
              statementType,
            });
          }

          return false;
        }
      },
    });
  }

  return { decorations, mergedPasteRange, doc };
}

/**
 * Expand the merged range to cover everything between the nearest complete
 * statements on either side, absorb non-complete decorations that fall inside,
 * and add the final merged incomplete bubble.
 */
function expandMergedRange(
  decorations: StatementDecoration[],
  mergedPasteRange: { from: number; to: number },
  doc: string,
): {
  decorations: StatementDecoration[];
  mergedPasteRange: { from: number; to: number };
} {
  const completeBoundaries = decorations
    .filter((dec) => dec.statementType === 'complete')
    .sort((a, b) => a.from - b.from);

  // Find the rightmost complete statement that ends before the merged range.
  let leftBoundary =
    completeBoundaries.findLast((c) => c.to <= mergedPasteRange.from)?.to ?? 0;

  // Find the leftmost complete statement that starts after the merged range.
  let rightBoundary =
    completeBoundaries.find((c) => c.from >= mergedPasteRange.to)?.from ??
    doc.length;

  // Trim whitespace from the boundaries so the bubble doesn't include
  // surrounding spaces.
  const leftGap = doc.slice(leftBoundary, mergedPasteRange.from);
  leftBoundary += leftGap.length - leftGap.trimStart().length;

  const rightGap = doc.slice(mergedPasteRange.to, rightBoundary);
  rightBoundary -= rightGap.length - rightGap.trimEnd().length;

  const expanded = {
    from: Math.min(mergedPasteRange.from, leftBoundary),
    to: Math.max(mergedPasteRange.to, rightBoundary),
  };

  // Drop any non-complete decorations that now fall inside the expanded
  // merged range, then add the merged incomplete bubble.
  const filtered = decorations.filter(
    (dec) =>
      dec.statementType === 'complete' ||
      dec.to <= expanded.from ||
      dec.from >= expanded.to,
  );

  filtered.push({
    from: expanded.from,
    to: expanded.to,
    mark: incompleteStatementMark,
    statementType: 'incomplete',
  });

  return { decorations: filtered, mergedPasteRange: expanded };
}

/**
 * Collect decorations for all filter statements, merging statements that
 * overlap or touch the pasted range (when it contains special characters)
 * into a single incomplete statement bubble.
 */
function collectStatementDecorations(
  view: EditorView,
  pastedRange: { from: number; to: number } | undefined,
): {
  decorations: StatementDecoration[];
  mergedPasteRange: { from: number; to: number } | null;
} {
  const rawDecorations = collectRawDecorations(view, pastedRange);
  let { decorations, mergedPasteRange } = rawDecorations;
  const { doc } = rawDecorations;

  // Initialize the merged range from the pasted range if no statement merged
  // with it in the first pass.
  if (!mergedPasteRange && pastedRange) {
    mergedPasteRange = { from: pastedRange.from, to: pastedRange.to };
  }

  if (mergedPasteRange) {
    const expanded = expandMergedRange(decorations, mergedPasteRange, doc);
    decorations = expanded.decorations;
    mergedPasteRange = expanded.mergedPasteRange;
  }

  return { decorations, mergedPasteRange };
}

/**
 * Create a range set with decorations for all the filter statements.
 * @internal
 */
export function createFilterStatementDecorations(view: EditorView) {
  const builder = new RangeSetBuilder<Decoration>();

  const pastingStateField = view?.state.field(pastingMode, false);

  // Pasted content with special characters gets an incomplete statement bubble
  // around the whole statement and neutral text color via pastingMark.
  // Normal pasted content stays inside its statement bubble and inherits
  // syntax-highlighting colors (blue for keys, black for values, etc.).
  const pastedContentHasSpecialChars =
    pastingStateField?.range !== undefined &&
    needsEscapingRegex.test(
      view.state.doc.sliceString(
        pastingStateField.range.from,
        pastingStateField.range.to,
      ),
    );

  const { decorations, mergedPasteRange } = collectStatementDecorations(
    view,
    pastedContentHasSpecialChars ? pastingStateField?.range : undefined,
  );

  const allDecorations = decorations;

  // Only apply the pastingMark (which overrides syntax colors to neutral) when
  // the pasted content contains special characters. The mark covers the entire
  // merged bubble range so that all text (including existing key/value text
  // adjacent to the paste) gets neutral coloring inside the incomplete bubble.
  if (
    pastedContentHasSpecialChars &&
    pastingStateField?.pastingInProgress &&
    pastingStateField.range
  ) {
    const pastingMarkRange = mergedPasteRange ?? pastingStateField.range;

    for (const { from, to } of view.visibleRanges) {
      if (from <= pastingMarkRange.from && to >= pastingMarkRange.to) {
        // only add the pasting decoration if the pasted range is visible
        // to avoid crashing when e.g. a delete event happens while pasting and
        // trying to add a statement bubble for content that is not there anymore
        allDecorations.push({
          from: pastingMarkRange.from,
          to: pastingMarkRange.to,
          mark: pastingMark,
          statementType: 'complete',
        });
      }
    }
  }

  allDecorations.sort((a, b) => a.from - b.from);

  for (const decoration of allDecorations) {
    builder.add(decoration.from, decoration.to, decoration.mark);
  }

  return builder.finish();
}

/** View plugin to wrap all filter statements in spans. */
export const FilterStatementDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createFilterStatementDecorations(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createFilterStatementDecorations(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
